import React, { useState, useEffect } from 'react';
import './Settings.css';
import DeleteForeverIcon from '@mui/icons-material/DeleteForever';

const Settings = ({ domain, setDomain, project, setProject, issueType, setIssueType }) => {
  const [isLocked, setIsLocked] = useState(true);
  const [detailsList, setDetailsList] = useState([]);

  // Fetch details from the API on component mount
  useEffect(() => {
    fetchDetails();
  }, []);

  // Fetch details from the API
  const fetchDetails = async () => {
    try {
      const response = await fetch('https://localhost:7216/api/Details');  // Replace with your actual API endpoint
      if (response.ok) {
        const data = await response.json();
        setDetailsList(data);  // Set the details into the state
      } else {
        console.error('Failed to fetch details:', response.statusText);
      }
    } catch (error) {
      console.error('Error fetching details:', error);
    }
  };

  // Handle delete action for a credential
  const handleDelete = async (detail) => {
    try {
      const response = await fetch('https://localhost:7216/api/Details/Delete', {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(detail),
      });

      if (response.ok) {
        setDetailsList(detailsList.filter((d) => d.Domain !== detail.Domain || d.Project !== detail.Project || d.IssueType !== detail.IssueType));
        alert('Credential deleted successfully');
      } else {
        const errorMessage = await response.text();
        console.error('Failed to delete credential:', errorMessage);
      }
    } catch (error) {
      console.error('Error deleting credential:', error);
    }
  };

  // Handle form submission (POST method for creating or updating credentials)
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!domain || !project || !issueType) {
      alert('All fields are required.');
      return;
    }

    const newCredential = { Domain: domain, Project: project, IssueType: issueType };

    try {
      const response = await fetch('https://localhost:7216/api/Details/Manage', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newCredential),
      });

      if (response.ok) {
        const { data } = await response.json();
        setDetailsList((prevDetails) => [...prevDetails, data]); // Add new credential to the list
        alert('Credential saved successfully');

        // Save the settings to localStorage after saving the credential
        localStorage.setItem('domain', domain);
        localStorage.setItem('project', project);
        localStorage.setItem('issueType', issueType);
      } else {
        const errorMessage = await response.text();
        console.error('Failed to save credential:', errorMessage);
        alert('Failed to save credential');
      }
    } catch (error) {
      console.error('Error saving credential:', error);
      alert('Error saving credential');
    }
  };

  const handleLockToggle = () => {
    setIsLocked(!isLocked);
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>

      {/* Form for submitting new or updated credentials */}
      <h3>Add or Update Credential</h3>
      <form onSubmit={handleSubmit}>
        <div>
          <label>
            Domain:
            <input
              type="text"
              value={domain}
              onChange={(e) => setDomain(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Project:
            <input
              type="text"
              value={project}
              onChange={(e) => setProject(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            Issue Type:
            <input
              type="text"
              value={issueType}
              onChange={(e) => setIssueType(e.target.value)}
              disabled={isLocked}
            />
          </label>
        </div>
        <div>
          <label>
            <input
              type="checkbox"
              checked={!isLocked}
              onChange={handleLockToggle}
            />
            Unlock to Edit
          </label>
        </div>
        <div>
          <button type="submit" disabled={isLocked}>Save Credential</button>
        </div>
      </form>

      {/* Display saved credentials */}
      <div className="details-list">
        <h3>Saved Credentials</h3>
        <table className="details-table">
          <thead>
            <tr>
              <th>Domain</th>
              <th>Project</th>
              <th>Issue Type</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {detailsList.length > 0 ? (
              detailsList.map((detail, index) => (
                <tr key={index}>
                  <td>{detail.Domain}</td>
                  <td>{detail.Project}</td>
                  <td>{detail.IssueType}</td>
                  <td>
                    <DeleteForeverIcon
                      onClick={() => handleDelete(detail)}
                      style={{ cursor: 'pointer', color: 'red' }}
                    />
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="4">No credentials available</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Settings;
